import { Component, computed, signal } from '@angular/core';
import { AXSafePipe } from '@acorex/core/pipes';

@Component({
  selector: 'app-trusted-content',
  imports: [AXSafePipe],
  template: `
    <article [innerHTML]="html() | safe: 'html'"></article>

    <iframe
      title="Trusted demo"
      [src]="demoUrl() | safe: 'resourceUrl'"
      loading="lazy"
    ></iframe>

    <a [href]="docsUrl | safe: 'url'" target="_blank" rel="noopener">
      Open docs
    </a>
  `,
})
export class TrustedContentComponent {
  html = signal('<p>Hello <strong>world</strong></p>');
  demoPath = signal('/demos/button');
  demoUrl = computed(() => `${this.demoPath()}?theme=light`);
  docsUrl = 'https://docs.acorexui.com/components/button';
}

