import { Component, inject, signal } from '@angular/core';
import { SafeHtml } from '@angular/platform-browser';
import { AXSafePipe } from '@acorex/core/pipes';

@Component({
  selector: 'app-icon-preview',
  template: `<span [innerHTML]="svg()"></span>`,
})
export class IconPreviewComponent {
  private safePipe = inject(AXSafePipe);

  svg = signal<SafeHtml | ''>('');

  async ngOnInit() {
    const svgMarkup = await this.loadTrustedSvg('home');
    this.svg.set(this.safePipe.transform(svgMarkup, 'html') as SafeHtml);
  }

  private loadTrustedSvg(name: string): Promise<string> {
    return Promise.resolve('<svg>...</svg>');
  }
}

